import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { authApi, auth } from '../services/api';

const S = {
  page: { display: 'flex', minHeight: 'calc(100vh - 64px)', background: 'var(--color-bg)' },
  left: {
    flex: 1, background: 'var(--color-dark)', padding: '64px 48px',
    display: 'flex', flexDirection: 'column', justifyContent: 'center',
    minWidth: 0,
  },
  right: {
    width: '52%', flexShrink: 0, padding: '64px 48px',
    display: 'flex', flexDirection: 'column', justifyContent: 'center',
    overflowY: 'auto',
  },
  logo: { fontSize: 'var(--text-2xl)', fontWeight: 900, color: '#fff', marginBottom: 8, letterSpacing: '-0.02em' },
  logoDot: { color: 'var(--color-gold)', marginLeft: 2 },
  leftTitle: { fontSize: 'clamp(1.75rem,3vw,2.5rem)', fontWeight: 'var(--weight-bold)', color: '#fff', letterSpacing: '-0.02em', marginBottom: 12 },
  leftDesc: { color: 'rgba(250,250,248,0.5)', lineHeight: 1.75, fontSize: 'var(--text-base)', marginBottom: 40 },
  valueProp: { display: 'flex', gap: 12, marginBottom: 16, alignItems: 'flex-start' },
  vpIcon: { width: 32, height: 32, borderRadius: '50%', background: 'rgba(181,154,106,0.15)', border: '1px solid rgba(181,154,106,0.3)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.9rem', flexShrink: 0 },
  vpText: { fontSize: 'var(--text-sm)', color: 'rgba(250,250,248,0.6)', lineHeight: 1.6, paddingTop: 6 },
  formTitle: { fontSize: 'var(--text-3xl)', fontWeight: 'var(--weight-bold)', color: 'var(--color-text-primary)', letterSpacing: 'var(--tracking-tight)', marginBottom: 6 },
  formSubtitle: { color: 'var(--color-text-muted)', fontSize: 'var(--text-sm)', marginBottom: 36 },
  error: { padding: '12px 16px', background: 'var(--color-error-light)', border: '1px solid var(--color-error)', borderRadius: 'var(--radius-md)', color: 'var(--color-error)', fontSize: 'var(--text-sm)', marginBottom: 20 },
  divider: { textAlign: 'center', fontSize: 'var(--text-sm)', color: 'var(--color-text-muted)', margin: '20px 0' },
};

const VALUE_PROPS = [
  { icon: '🧠', text: 'BuildPilot recommends the perfect dataset stack for your project.' },
  { icon: '📊', text: '32+ curated datasets across IT, Healthcare, Geography, Sports, and Electronics.' },
  { icon: '🔑', text: 'One API key. Every dataset. No per-endpoint authentication.' },
];

export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const login = async (e) => {
    e.preventDefault();
    if (!email.trim() || !password) { setError('Please enter your email and password.'); return; }
    setError('');
    setLoading(true);
    try {
      const res = await authApi.login(email.trim(), password);
      const d = res.data;
      auth.setTokens(d.access_token, d.refresh_token);
      auth.setUser({ email: d.email, username: d.username, id: d.user_id });
      navigate('/dashboard');
    } catch (e) {
      setError(e.message || 'Invalid email or password.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={S.page} className="page-enter">
      {/* Left panel */}
      <div style={S.left}>
        <div style={S.logo}>OmniCore<span style={S.logoDot}>.</span></div>
        <h2 style={S.leftTitle}>The Core of<br />Developer Data.</h2>
        <p style={S.leftDesc}>Sign in to access your datasets, API keys, and developer tools.</p>
        {VALUE_PROPS.map((v, i) => (
          <div key={i} style={S.valueProp}>
            <div style={S.vpIcon}>{v.icon}</div>
            <div style={S.vpText}>{v.text}</div>
          </div>
        ))}
      </div>

      {/* Right panel */}
      <div style={S.right}>
        <div style={{ maxWidth: 400, width: '100%', margin: '0 auto' }}>
          <h1 style={S.formTitle}>Welcome back</h1>
          <p style={S.formSubtitle}>Sign in to your OmniCore account.</p>

          {error && <div style={S.error}>{error}</div>}

          <form onSubmit={login}>
            <div className="form-group">
              <label className="label" htmlFor="login-email">Email</label>
              <input id="login-email" type="email" className="input" placeholder="you@example.com"
                value={email} onChange={e => setEmail(e.target.value)} autoFocus autoComplete="email" />
            </div>
            <div className="form-group">
              <label className="label" htmlFor="login-password">Password</label>
              <input id="login-password" type="password" className="input" placeholder="Your password"
                value={password} onChange={e => setPassword(e.target.value)} autoComplete="current-password" />
            </div>

            <button id="login-submit" type="submit" className="btn btn-primary btn-lg" style={{ width: '100%' }} disabled={loading}>
              {loading ? <><span className="spinner spinner-sm" /> Signing in…</> : 'Sign In'}
            </button>
          </form>

          <div style={S.divider}>
            Don't have an account? <Link to="/register" style={{ color: 'var(--color-gold-dark)', fontWeight: 'var(--weight-medium)' }}>Sign up for free</Link>
          </div>
        </div>
      </div>
    </div>
  );
}
